PREFIX uni: <http://university.org/ontology/>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>

SELECT ?professorName (GROUP_CONCAT(DISTINCT ?country; separator=", ") AS ?countries)
WHERE {
  # --- Full professors ---
  ?prof a uni:Person ;
        uni:hasName ?professorName ;
        uni:role ?role .
  FILTER(STRSTARTS(?role, "Professor"))   # excludes "Assistant/Associate Professor ..."

  # --- Countries of every department the professor works in ---
  ?prof uni:worksIn ?anyDept .
  ?anyDept uni:belongsTo ?anyUni .
  ?anyUni uni:locatedInCountry ?country .

  # --- Criterion 2: works in at least one department located in an EU country ---
  FILTER EXISTS {
    ?prof uni:worksIn ?euDept .
    ?euDept uni:belongsTo ?euUni .
    ?euUni uni:locatedInCountry ?euCountry .
    FILTER(?euCountry IN (
