               uni:hasEnrollmentDate ?enroll .
      # already enrolled by the reference date
      FILTER(?enroll <= "2025-08-16"^^xsd:date)
      # and not yet graduated as of the reference date -> currently enrolled
      FILTER NOT EXISTS {
        ?student uni:hasGraduationDate ?grad .
        FILTER(?grad < "2025-08-16"^^xsd:date)
      }
    }
    GROUP BY ?bigDept
    HAVING(COUNT(DISTINCT ?student) > 10)
  }
